import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"F14｜負債結構與償債壓力測試 — 8103 瀚荃","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F14_負債結構與償債壓力測試.md","filePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F14_負債結構與償債壓力測試.md"}'),o={name:"審計報告庫/財務審計/8103_瀚荃/20260425/F14_負債結構與償債壓力測試.md"};function n(h,t,l,s,i,g){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="f14-負債結構與償債壓力測試-—-8103-瀚荃" tabindex="-1">F14｜負債結構與償債壓力測試 — 8103 瀚荃 <a class="header-anchor" href="#f14-負債結構與償債壓力測試-—-8103-瀚荃" aria-label="Permalink to &quot;F14｜負債結構與償債壓力測試 — 8103 瀚荃&quot;">​</a></h1><blockquote><p><strong>審計日期</strong>：2026-04-25<br><strong>審計專家</strong>：投資研究員（L3）<br><strong>數據截止</strong>：2025Q4（2025-12-31）<br><strong>評級</strong>：<strong>A 級（低風險）</strong></p></blockquote><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>瀚荃（8103）的負債結構是否處於安全範圍？短期與長期的償債能力是否足以應對營運波動？是否存在潛在的流動性風險？</p><hr><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>瀚荃負債比從2023Q2的41.7%持續降至2025Q4的35.8%，公司債4.93億已於2023Q4全數清償，有息負債佔資產比僅8.4%。淨現金部位高達19.7億（現金24.7億vs有息負債4.97億），ICR全年維持7.7x以上，FCF年達13.6億。綜合評級：A級（低風險），償債能力無任何疑慮。</p><hr><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A 級（低風險）</strong></p><table tabindex="0"><thead><tr><th>評估維度</th><th style="text-align:center;">評分</th><th>依據</th></tr></thead><tbody><tr><td>負債結構</td><td style="text-align:center;">A</td><td>負債比35.8%，有息負債佔資產比僅8.4%，以營業性負債為主</td></tr><tr><td>利息覆蓋</td><td style="text-align:center;">A</td><td>全年ICR最低4.8x、最新7.7x，償債緩衝充裕</td></tr><tr><td>現金覆蓋</td><td style="text-align:center;">A</td><td>現金/有息負債=4.97倍，淨現金19.7億</td></tr><tr><td>壓力測試</td><td style="text-align:center;">A</td><td>營收-20%情境下ICR仍有4.3x、FCF仍正</td></tr><tr><td>短期流動性</td><td style="text-align:center;">A</td><td>流動比2.87、速動比2.55，短期無虞</td></tr></tbody></table><hr><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、負債結構全景拆解" tabindex="-1">一、負債結構全景拆解 <a class="header-anchor" href="#一、負債結構全景拆解" aria-label="Permalink to &quot;一、負債結構全景拆解&quot;">​</a></h3><h4 id="_1-1-負債比率趨勢-2023q2→2025q4" tabindex="-1">1.1 負債比率趨勢（2023Q2→2025Q4） <a class="header-anchor" href="#_1-1-負債比率趨勢-2023q2→2025q4" aria-label="Permalink to &quot;1.1 負債比率趨勢（2023Q2→2025Q4）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>期別</th><th>負債比</th><th>權益比</th><th>有息負債佔資產比</th><th>流動比</th><th>速動比</th></tr></thead><tbody><tr><td>2023Q2</td><td>41.7%</td><td>58.3%</td><td>14.5%</td><td>3.32</td><td>2.92</td></tr><tr><td>2023Q4</td><td>38.8%</td><td>61.2%</td><td>4.8%</td><td>—</td><td>—</td></tr><tr><td>2024Q4</td><td>30.1%</td><td>69.9%</td><td>4.4%</td><td>3.62</td><td>3.24</td></tr><tr><td>2025Q2</td><td>37.9%</td><td>62.1%</td><td>7.3%</td><td>2.73</td><td>2.47</td></tr><tr><td>2025Q3</td><td>37.4%</td><td>62.6%</td><td>8.3%</td><td>2.68</td><td>2.42</td></tr><tr><td><strong>2025Q4</strong></td><td><strong>35.8%</strong></td><td><strong>64.2%</strong></td><td><strong>8.4%</strong></td><td><strong>2.87</strong></td><td><strong>2.55</strong></td></tr></tbody></table><p><strong>核心觀察</strong>：負債比從41.7%持續下降至35.8%，反映主動降槓桿策略成效。2023Q4公司債4.93億全數償還完畢為關鍵改善事件。2025年短期借款從2.3億升至4.5億，主要用於營運周轉，但整體有息負債佔資產比仍維持在8.4%的低水準。</p><h4 id="_1-2-有息負債明細-2025q4" tabindex="-1">1.2 有息負債明細（2025Q4） <a class="header-anchor" href="#_1-2-有息負債明細-2025q4" aria-label="Permalink to &quot;1.2 有息負債明細（2025Q4）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>項目</th><th>金額（百萬）</th><th>佔總資產比</th></tr></thead><tbody><tr><td>短期借款</td><td>450.0</td><td>7.60%</td></tr><tr><td>長期借款</td><td>47.4</td><td>0.80%</td></tr><tr><td>應付公司債</td><td>0.0</td><td>0.00%</td></tr><tr><td><strong>合計</strong></td><td><strong>497.4</strong></td><td><strong>8.40%</strong></td></tr></tbody></table><p>相比總資產59.2億，有息負債僅4.97億，佔比極低。公司債已全數清償，以短期周轉金為主，到期結構極為安全。</p><h4 id="_1-3-負債組成質性分析" tabindex="-1">1.3 負債組成質性分析 <a class="header-anchor" href="#_1-3-負債組成質性分析" aria-label="Permalink to &quot;1.3 負債組成質性分析&quot;">​</a></h4><p>2025Q4負債總額21.2億中：應付帳款6.86億（32.3%，屬正常營業負債）、其他應付款2.74億（12.9%）、短期借款4.50億（21.2%）、本期所得稅負債0.88億（4.1%）、長期借款0.47億（2.2%）、其他非流動負債0.59億（2.8%含租賃及退休金）。營業性負債佔比超36%為良性，金融負債僅23.4%，償債壓力極輕。</p><h3 id="二、利息覆蓋倍數與利息壓力" tabindex="-1">二、利息覆蓋倍數與利息壓力 <a class="header-anchor" href="#二、利息覆蓋倍數與利息壓力" aria-label="Permalink to &quot;二、利息覆蓋倍數與利息壓力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>期別</th><th>營業利益（百萬）</th><th>利息費用（百萬）</th><th>ICR（倍）</th></tr></thead><tbody><tr><td>2024Q4</td><td>57.2</td><td>12.0</td><td>4.8x</td></tr><tr><td>2025Q1</td><td>66.6</td><td>2.6</td><td>25.9x</td></tr><tr><td>2025Q2</td><td>140.2</td><td>5.7</td><td>24.5x</td></tr><tr><td>2025Q3</td><td>139.7</td><td>9.2</td><td>15.2x</td></tr><tr><td><strong>2025Q4</strong></td><td><strong>103.0</strong></td><td><strong>13.4</strong></td><td><strong>7.7x</strong></td></tr></tbody></table><p>全年ICR均遠高於3倍安全線，最低4.8x。利息費用全年約3,073萬，佔營業利益僅2.7%。加權借款利率約1.1%（年化），利率極低。</p><h3 id="三、自由現金流與償債能力" tabindex="-1">三、自由現金流與償債能力 <a class="header-anchor" href="#三、自由現金流與償債能力" aria-label="Permalink to &quot;三、自由現金流與償債能力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>期別</th><th>OCF（百萬）</th><th>CapEx（百萬）</th><th>FCF（百萬）</th></tr></thead><tbody><tr><td>2025Q4</td><td>646</td><td>127</td><td>519</td></tr><tr><td><strong>2025全年</strong></td><td><strong>1,633</strong></td><td><strong>270</strong></td><td><strong>1,363</strong></td></tr></tbody></table><p><strong>償債能力矩陣</strong>：有息負債/年度FCF=0.36年（不到5個月可清償全部有息負債）；淨負債=4.97億-24.7億=-19.7億（淨現金）；現金/有息負債=4.97x；OCF/短期借款=3.6x。</p><h3 id="四、壓力測試" tabindex="-1">四、壓力測試 <a class="header-anchor" href="#四、壓力測試" aria-label="Permalink to &quot;四、壓力測試&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情境</th><th>壓力ICR</th><th>FCF</th><th style="text-align:center;">風險等級</th></tr></thead><tbody><tr><td>營收-20%</td><td>4.3x</td><td>正（年化約3億）</td><td style="text-align:center;">低</td></tr><tr><td>-20%+利率+3pp</td><td>3.2x</td><td>正</td><td style="text-align:center;">中低</td></tr><tr><td>極端（-50%營收+利率飆升）</td><td>1.5x</td><td>正（靠現金儲備）</td><td style="text-align:center;">中</td></tr></tbody></table><p>即使營收腰斬，現金存量24.7億足以撐過2-3年極端低迷期。</p><hr><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="多頭視角-財務體質為護城河" tabindex="-1">多頭視角：財務體質為護城河 <a class="header-anchor" href="#多頭視角-財務體質為護城河" aria-label="Permalink to &quot;多頭視角：財務體質為護城河&quot;">​</a></h3><p>瀚荃的資產負債表在台股電子零組件同業中屬頂尖水準：淨現金19.7億、有息負債僅佔資產8.4%、ICR達7.7x。這種財務彈性賦予公司在景氣下行時逆勢擴產、低點併購或提高股利的能力。2023年公司債全數清償後，每年節省的利息費用直接轉化為盈餘改善。零公司債+低利率借款=最大的防禦型資產配置優勢。</p><h3 id="空頭視角-最極端的風險阻力" tabindex="-1">空頭視角：最極端的風險阻力 <a class="header-anchor" href="#空頭視角-最極端的風險阻力" aria-label="Permalink to &quot;空頭視角：最極端的風險阻力&quot;">​</a></h3><ol><li><strong>短期借款翻倍的警訊</strong>：短期借款從2.3億增至4.5億，若屬於結構性增加（非季節性），則營運資金需求正在擴大，可能反映存貨堆積或應收帳款週轉惡化。</li><li><strong>利率環境變化的不對稱風險</strong>：借款利率雖僅1.1%，但瀚荃短期借款佔有息負債90%，利率風險敞口完全暴露於貨幣市場。若央行升息3碼，年利息費用將增約1,200萬（對EPS影響約0.15元）。</li><li><strong>租賃負債隱性風險</strong>：使用權資產2.26億對應的租賃負債為固定支出，若越南/泰國廠營運未達預期，租賃成本將成為無法削減的固定負擔。</li><li><strong>應付帳款增長的雙面刃</strong>：從5.79億增至6.86億，若供應商縮短帳期（從60天降至30天），將一次性消耗約3.5億現金，雖不致命但會明顯壓縮FCF。</li></ol><h3 id="物理對策" tabindex="-1">物理對策 <a class="header-anchor" href="#物理對策" aria-label="Permalink to &quot;物理對策&quot;">​</a></h3><ul><li><strong>短期借款警戒線</strong>：突破8億時啟動債務結構重審</li><li><strong>ICR安全底線</strong>：連續2季低於5x時啟動應急方案</li><li><strong>利率風險對沖</strong>：建議將30%短期借款鎖定固定利率</li></ul><hr><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>數據項目</th><th>來源</th><th>查詢指令</th></tr></thead><tbody><tr><td>資產負債表</td><td>FinMind</td><td><code>balance_sheet 8103 2023-04-25 2026-04-25 --df</code></td></tr><tr><td>綜合損益表</td><td>FinMind</td><td><code>finance 8103 2024-06-01 2026-04-25 --df</code></td></tr><tr><td>現金流量表</td><td>FinMind</td><td><code>cash_flow 8103 2024-06-01 2026-04-25 --df</code></td></tr><tr><td>PER/PBR</td><td>FinMind</td><td><code>per 8103 2024-06-01 2026-04-25 --df</code></td></tr><tr><td>Python驗算</td><td>本地</td><td><code>/tmp/8103_calc.py</code></td></tr></tbody></table><hr><p><strong>審計完成時間</strong>：2026-04-25<br><strong>報告寫入路徑</strong>：<code>/Users/kaipro/.openclaw/skills/NEW_Deep32Q/審計報告庫/8103_瀚荃/20260425/財務組/F14_負債結構與償債壓力測試.md</code></p>',45)])])}const x=d(o,[["render",n]]);export{b as __pageData,x as default};
